import json,heapq
from collections import defaultdict
from cost_model import CostModel, align, HEADS, HIDDEN

def sumsq(a,n): return n*a*a + a*n*(n-1) + (n*(n-1)*(2*n-1))//6
def dcost(S,G): return 1.0*sumsq(S,G)+2048.0*(G*S+G*(G-1)/2)
def dlat(S,G): return 0.0012*sumsq(S,G)+2.4576*(G*S+G*(G-1)/2)
def plat(S): return 0.002*S*S+6.144*S
def seqlat(S,G): return plat(S)+dlat(S,G)+8.0

class Batch:
    __slots__=('ids','S','G','N','sumG','cost','pad','sq','alive')
    def __init__(s,ids,S,G,sumG):
        s.ids=ids; s.S=S; s.G=G; s.N=len(ids); s.sumG=sumG
        s.cost=s.N*dcost(S,G); s.pad=s.N*G-sumG; s.sq=seqlat(S,G); s.alive=True

def build(reqs):
    g=defaultdict(list)
    for r in reqs:
        S=align(r['prompt_len'],64); g[(S,r['gen_len'])].append(r['request_id'])
    return [Batch(ids,S,G,G*len(ids)) for (S,G),ids in g.items()]

def merged(a,b):
    S=max(a.S,b.S);G=max(a.G,b.G);N=a.N+b.N;sumG=a.sumG+b.sumG
    return S,G,N,sumG,N*dcost(S,G),N*G-sumG,seqlat(S,G)

def optimize(reqs,cost_cap_int,pad_cap,lat_cap,lam_c,lam_p,gwin,swin):
    batches=build(reqs)
    tot_cost=sum(b.cost for b in batches); tot_pad=sum(b.pad for b in batches)
    ver=[0]*len(batches)
    def neigh(i):
        bi=batches[i]
        for j in range(len(batches)):
            if j==i or not batches[j].alive: continue
            bj=batches[j]
            if abs(bi.S-bj.S)<=swin and abs(bi.G-bj.G)<=gwin: yield j
    def sc(a,b):
        S,G,N,sumG,cost,pad,sq=merged(a,b)
        dseq=sq-a.sq-b.sq; dcst=cost-a.cost-b.cost-1e7; dpd=pad-a.pad-b.pad
        return dseq+lam_c*max(0,dcst)+lam_p*max(0,dpd),dseq,dcst,dpd,sq
    heap=[]
    for i in range(len(batches)):
        if not batches[i].alive: continue
        for j in neigh(i):
            if j<=i: continue
            s,dseq,dcst,dpd,sq=sc(batches[i],batches[j])
            if dseq<0 and sq<lat_cap: heapq.heappush(heap,(s,i,ver[i],j,ver[j]))
    while heap:
        s,i,vi,j,vj=heapq.heappop(heap)
        if not batches[i].alive or not batches[j].alive: continue
        if ver[i]!=vi or ver[j]!=vj: continue
        a,b=batches[i],batches[j]
        S,G,N,sumG,cost,pad,sq=merged(a,b)
        dcst=cost-a.cost-b.cost-1e7; dpd=pad-a.pad-b.pad; dseq=sq-a.sq-b.sq
        if dseq>=0 or sq>=lat_cap: continue
        if tot_cost+dcst>cost_cap_int or tot_pad+dpd>pad_cap: continue
        a.ids=a.ids+b.ids;a.S=S;a.G=G;a.N=N;a.sumG=sumG;a.cost=cost;a.pad=pad;a.sq=sq
        tot_cost+=dcst;tot_pad+=dpd;b.alive=False;ver[i]+=1;ver[j]+=1
        for k in neigh(i):
            s2,dseq2,dcst2,dpd2,sq2=sc(batches[i],batches[k])
            if dseq2<0 and sq2<lat_cap:
                lo,hi=(i,k) if i<k else (k,i)
                heapq.heappush(heap,(s2,lo,ver[lo],hi,ver[hi]))
    return [b for b in batches if b.alive]

def reps_for(reqs):
    aligned=sorted(set(align(r['prompt_len'],64) for r in reqs))
    K=min(8,len(aligned))
    return sorted({aligned[min(len(aligned)-1,int((i+1)*len(aligned)/K)-1)] for i in range(K)})

def evaluate(batches,reqs,reps):
    rd={r['request_id']:r for r in reqs}
    def assign(s):
        for r in reps:
            if r>=s: return r
        return reps[-1]
    recs=[]
    for bi,bt in enumerate(batches):
        maxs=max(align(rd[rid]['prompt_len'],64) for rid in bt.ids)
        rep=assign(maxs)
        for rid in bt.ids:
            recs.append({'request_id':rid,'batch_id':f'b-{bi:05d}','shape':{'seq_align':rep,'heads_align':HEADS,'hidden_align':HIDDEN}})
