            cost_cap_int=0.99*C-fx-1e7*1  # overhead handled inside? overhead added per batch in model
            # model adds Kbatch_overhead 1e7*nbatch; our tot_cost excludes it. add after.
            batches=optimize(reqs,C, 0.985*P*real - padprefill*0, 0.99*L, lam_c,lam_p, gwin=10**9 if False else 300, swin=400)
            recs,m=evaluate(batches,reqs,reps)
            ok=(m['cost']<C and m['pad_ratio']<P and m['p95_latency_ms']<L and m['sequential_timecost']<SQ)
            marg=min((C-m['cost'])/C,(P-m['pad_ratio'])/P,(L-m['p95_latency_ms'])/L,(SQ-m['sequential_timecost'])/SQ)
            if ok and (best is None or marg>best[0]):
                best=(marg,lam_c,lam_p,m,len(batches),recs)
    if best:
        marg,lc,lp,m,nb,recs=best
